import React, { useRef } from "react";
import { Navbar, Button, TextInput } from "flowbite-react";
import { Link } from "react-router-dom";
import { useState } from "react";
import { api, api_key } from "../api";

const Header = () => {
const movieName = useRef("")
const searchMovie =async () =>{
  console.log(movieName.current.value)
  if(movieName.current.value !==""){
    const res = await api.get(`/search/movie?api_key=${api_key}&query=${movieName.current.value}`);
    console.log(res.data)
}
    return (
      <div>
        <Navbar className="" fluid rounded>
          <Link to="/">
            <span className="self-center whitespace-nowrap text-xl font-semibold dark:text-white">
              Movie Channel
            </span>
          </Link>
          <div className="flex md:order-2">
            <form
              action=""
              className="text-black flex items-center justify-center"
            >
              <TextInput
                placeholder="Search..." />
               
             
              <Button
                className="ms-2"
               onClick={()=>searchMovie()}
                color="dark"
                type="button"
              >
                Click
              </Button>
            </form>
          </div>
        </Navbar>
      </div>
    );
  }};


export default Header;
